INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('16049636-5386-5536-a9aa-45c972832f09', '2a29f581-ded3-4a51-89ec-e8ceb4ebb8fd', '___ is a very large continent.', '美洲是一個非常大的大陸。', 'America', 'Asia', 'Africa', 'Europe', '專有名詞，指美國或美洲。', 'America → 美洲大陸。', '2026-07-06 14:01:13', '2026-07-06 14:01:13'),
('e62841c5-4ec7-5a67-9a23-98623cd616bd', 'c74a6285-2ce5-4847-b8c6-f6de69e85c1c', 'Scientists travel to ___ to study the effects of global warming on the massive ice sheets.', '科學家前往南極洲，以研究全球暖化對巨大冰蓋的影響。', 'Antarctica', 'Australia', 'Africa', 'Asia', '字首 anti- 代表「相反」，因此 Antarctica 與 Arctic (北極) 相對。', 'Arctic 為北極，加上 anti- (相反) → Antarctica 即為南極。', '2026-07-06 21:44:39', '2026-07-06 21:44:39'),
('877a07ec-c298-5ee1-b12d-c1dace7e3d7d', 'f2172994-3693-4f67-ad7f-27f5ff11a05f', 'In academic writing, it is important to provide the full term before using its ___ to avoid confusion.', '在學術寫作中，在使用其縮寫之前提供完整術語以避免混淆是很重要的。', 'abbreviation', 'explanation', 'application', 'illustration', 'ab- (離開/偏離) + brevi (短) + -ation (名詞字尾) → 使字變短的過程', 'ab (離開) + brevi (短) + ation (名詞字尾) → 把字變短 → 縮寫', '2026-07-06 15:52:33', '2026-07-06 15:52:33'),
('05315c5a-dd37-5f56-be0b-c363f2c53385', '1f35212d-c91a-4e09-9a48-17e80ddcac69', '___ the latest news report, the government will implement new environmental policies next month.', '根據最新的新聞報導，政府將於下個月實施新的環境政策。', 'According to', 'Instead of', 'Due to', 'Regardless of', 'accord (同意/一致) + ing (分詞) + to (介係詞) → 依照、根據。', '記住 accord 有「一致」的意思，according to 就是「與...之內容一致」→ 根據。', '2026-07-06 16:54:06', '2026-07-06 16:54:06'),
('e2d7cdd0-edb5-5c18-9946-05a91852412d', 'a926aedb-8520-4ffd-a135-7949283a3088', 'In a dictionary, if you see the abbreviation ___ next to a word, it indicates that the word functions as an adverb.', '在字典中，如果你在一個單字旁邊看到縮寫 ___，它表示該單字的功能是副詞。', 'adv.', 'n.', 'v.', 'adj.', 'adv. 是 adverb (副詞) 的縮寫。', '記住 adv. → adverb (副詞)，常用於文法標註。', '2026-07-06 18:03:16', '2026-07-06 18:03:16'),
('15dfc502-876c-5215-af1f-307918584dd5', '8c46583a-cf12-40a5-a096-777b6cfae86f', 'She started her job a month ___.', '她一個月前開始工作。', 'ago', 'still', 'ever', 'fast', 'ago 表示從現在算起往回推的時間，通常用於過去式句型。', '想像事情已經走(go)遠了 → 以前。', '2026-07-06 13:30:30', '2026-07-06 13:30:30'),
('5163d746-c1db-5585-9590-db63a7bf5011', '44cdbfbb-9e68-4625-ae4a-6660c84b8bb5', 'The rapid buildup of ___ in the region has raised concerns about a potential military conflict.', '該地區軍備的快速擴張，引發了對潛在軍事衝突的擔憂。', 'arms', 'crops', 'songs', 'tools', 'arms 作為複數名詞，除了指手臂，也常用來指代「武器」或「軍備」。', '看到 arms 就想到士兵在邊境堆疊武器。', '2026-07-07 00:01:06', '2026-07-07 00:01:06'),
('703af073-72c6-5bb3-b11c-00ef318702f9', '9490faa0-af9d-4259-9aa2-a4b18dc0f023', 'My mother will ___ me to clean my room.', '我媽媽會要求我打掃房間。', 'ask', 'say', 'call', 'watch', 'ask 在此用法表示「要求」某人做某事 (ask someone to do something)。', 'ask → 請求、詢問、要求。', '2026-07-06 14:55:46', '2026-07-06 14:55:46'),
('c52a4364-8c90-51cd-9a0f-bcc2cf8e9371', '62b52b58-2433-426f-b484-bcc97f9858bd', 'The flight ___ provided excellent service by ensuring all passengers were comfortable during the long journey.', '空服員在長途旅程中確保所有乘客都感到舒適，提供了卓越的服務。', 'attendant', 'manager', 'pilot', 'passenger', 'attend (參加/照料) + -ant (表示「人」的字尾) → 服務員、出席者', '想像在參加 (attend) 活動的人或在旁邊照料的人，就是 attendant (出席者或服務員)。', '2026-07-07 02:17:37', '2026-07-07 02:17:37'),
('cd9cf57b-e2d1-524e-aaea-a290627f4855', '4d3668e9-d914-4bd5-8081-70fedc7c9b69', 'Students are expected to pay close ___ to the teacher''s instructions during the experiment.', '學生在實驗過程中應密切注意老師的指示。', 'attention', 'respect', 'interest', 'patience', 'ad- (向/往) + tend (伸展) → 將心神伸向某個目標 → 注意。', '記住固定片語 ''pay attention to'' (注意)，並想像你的注意力正『伸展』向某個目標。', '2026-07-07 02:19:32', '2026-07-07 02:19:32'),
('d79a5387-187e-53bf-aeb7-be6b1a9c21dd', '0485a932-fbde-4613-9778-96d685fbaa97', 'The company is preparing for an annual ___ to ensure all financial records are accurate.', '公司正在準備年度審計，以確保所有的財務記錄都是準確的。', 'audit', 'budget', 'profit', 'contract', '字根 aud (聽) → 透過聽取報告來核對帳目。', '想像審計師在聽取報告後進行查帳。', '2026-07-07 03:30:10', '2026-07-07 03:30:10'),
('cb136a05-f0f2-5883-aa67-417ae08a20c1', 'd56c060f-f3fd-4881-9730-853ebc66dac9', 'My ___ is a close friend of my mother, so she often visits our home during the holidays.', '我的伯母是我母親的好友，所以她在假期時經常來我們家拜訪。', 'auntie', 'dentist', 'athlete', 'chef', 'aunt (姨、姑、伯母) + -ie (常用於親暱稱呼的小稱後綴)', 'auntie 結尾的 -ie 讓語氣聽起來更親切，就像在稱呼一位親近的伯母或阿姨。', '2026-07-07 03:37:20', '2026-07-07 03:37:20'),
('06e59351-042e-5789-bb27-af5c0f11f5bd', '1d12a4c6-52e5-427a-bb71-cba0d95465e2', 'Because of the heavy rain, the teacher decided to ___ the soccer game today.', '因為大雨，老師決定取消今天的足球比賽。', 'cancel', 'start', 'finish', 'follow', 'cancel (取消) 指的是撤銷、中止或取消原本已經安排好的計畫或活動。', '想像你在訂餐時發現點錯了，趕快打電話去 cancel (取消) 它，以免浪費錢。', '2026-07-07 02:18:11', '2026-07-07 02:18:11'),
('d0288887-297a-5095-877b-a97866dd04f1', '74c75a5a-639c-4408-8fcb-c87179af39ed', 'The soldiers must follow the captain''s ___ immediately.', '士兵們必須立即服從隊長的命令。', 'command', 'question', 'dream', 'gift', 'com (一起) + mand (命令) → command (命令/指揮)。', '想像在一個 command center (指揮中心) 裡面，長官正在發號施令。', '2026-07-07 05:20:17', '2026-07-07 05:20:17'),
('70759bea-970e-5d0f-bea7-2da1a3c68049', '5e24d6b2-ab19-4967-a2a4-0c356cccfb9e', 'The ___ is flying high in the sky to look for food.', '那隻___正在高空中飛翔，尋找食物。', 'eagle', 'rabbit', 'dolphin', 'monkey', 'eagle 為名詞，指老鷹。', '看到 sky 和 fly 就聯想到 eagle。', '2026-07-07 02:57:38', '2026-07-07 02:57:38'),
('b5dca5e5-ff50-5069-ad9a-43e20fb124e9', 'cd27aab0-de60-4464-ba48-418a869eafe9', 'Don''t ___ too much candy.', '不要吃太多糖果。', 'eat', 'wash', 'jump', 'fly', '此為基礎動詞，無特定字根。', 'Candy (糖果) 很甜 → 要小心 eat (吃) 的量。', '2026-07-07 03:11:34', '2026-07-07 03:11:34'),
('78007eb3-aaf6-5d4d-a772-653271d5d0e5', '2a2b1622-df4b-45d7-b3be-b82090cf215a', 'The book gives many ___ of how to cook.', '這本書提供了許多關於如何烹飪的例子。', 'examples', 'ideas', 'errors', 'images', 'ex (向外) + ample (充足的)', '把充足的事情拿出來，就是「例子」。', '2026-07-07 05:01:25', '2026-07-07 05:01:25'),
('99635709-c515-5b3b-bc07-4cdfe19b64c9', 'a75b25f5-3af5-4ed0-a8d7-5e18c501992b', 'Do you have any ___ pencils? I forgot mine at home.', '你有任何額外的鉛筆嗎？我把我的忘在家裡了。', 'extra', 'small', 'long', 'old', 'ex- 表示「超出」，tra 表示「超越」，合起來就是「額外的」。', '看到 extra，可以聯想 extra-large (加大號)，就是比標準的還要「多」或「大」。', '2026-07-07 05:34:07', '2026-07-07 05:34:07'),
('a3fde7cf-6038-5b8d-b029-af6935c1ec09', '8014755c-2a80-466f-a06a-c53a888c0b81', 'My brother is very tall. ___ is a basketball player.', '我的哥哥很高。他是籃球選手。', 'He', 'She', 'It', 'They', '人稱代名詞，用於指代男性單數。', '看到男生 (brother) → 用 He。', '2026-07-06 10:34:37', '2026-07-06 10:34:37'),
('2e3d39b4-7356-5804-8b00-89553b379631', '595e0908-47b5-4b28-98b7-8887a86c7901', 'Some ___ like to play basketball.', '有些人喜歡打籃球。', 'people', 'animals', 'birds', 'cats', '無特定字根', 'people → 人們 (指一群人)', '2026-07-06 10:39:14', '2026-07-06 10:39:14'),
('7c232e63-4f83-5263-b4d4-e92e13e57c5d', '74449081-948e-4337-b24b-e50b8a25cddf', '___ kind of music do you like?', '你喜歡什麼種類的音樂？', 'what', 'which', 'some', 'many', '這是一個疑問形容詞，用來修飾後面的名詞。', '看到問句想問『什麼』，就找 what！', '2026-07-05 11:57:46', '2026-07-05 11:57:46');
